// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  // GET REQUESTS
  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // SEARCH WORKERS
  const searchWorkers = async (workType) => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter((w) =>
        w.skills.includes(workType)
      );

      setWorkers(filtered);

    } catch (err) {
      console.log(err);
    }
  };

  // SEND REQUEST
  const sendRequest = async () => {
    if (!form.workType || !form.labourId || !form.location || !form.date) {
      return alert("Please fill all fields");
    }

    try {
      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"]
        }
      );

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);
      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  // CUSTOMER DECISION
  const customerDecision = async (id, decision) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/customer-decision/${id}`,
        { decision }
      );

      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  // FEEDBACK
  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) {
      return alert("Please enter rating and review");
    }

    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.wrapper}>

        {/* LEFT PANEL */}
        <div style={styles.panel}>

          <h2 style={styles.title}>Hire Worker</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({ ...form, workType: e.target.value });
              searchWorkers(e.target.value);
            }}
          >
            <option value="">Select Work</option>
            {jobs.map((job, i) => (
              <option key={i} value={job}>{job}</option>
            ))}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {
                const w = workers.find(x => x._id === e.target.value);
                if (!w) return;

                setForm({
                  ...form,
                  labourId: w._id,
                  labourName: w.name
                });
              }}
            >
              <option>Select Worker</option>
              {workers.map(w => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Location"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <button style={styles.btn} onClick={sendRequest}>
            Send Request
          </button>

        </div>

        {/* RIGHT PANEL */}
        <div style={styles.panel}>

          <h2 style={styles.title}>My Requests</h2>

          {requests.length === 0 && (
            <p style={{ color: "#aaa" }}>No Requests Found</p>
          )}

          {requests.map(req => (
            <div key={req._id} style={styles.card}>

              <h3 style={{ color: "#f97316" }}>
                {req.labourName}
              </h3>

              <p>Work: {req.workType}</p>
              <p>Location: {req.location}</p>
              <p>Date: {req.date}</p>

              <p>Status: {req.status}</p>

              {req.labourResponse === "Accepted" &&
                req.customerDecision === "Waiting" && (

                <div style={styles.row}>

                  <button
                    style={styles.accept}
                    onClick={() => customerDecision(req._id, "Accepted")}
                  >
                    Accept
                  </button>

                  <button
                    style={styles.reject}
                    onClick={() => customerDecision(req._id, "Rejected")}
                  >
                    Reject
                  </button>

                </div>
              )}

              {req.customerDecision === "Accepted" && (
                <div>

                  <input
                    type="number"
                    min="1"
                    max="5"
                    placeholder="Rating"
                    style={styles.input}
                    onChange={(e) =>
                      setRequests(requests.map(i =>
                        i._id === req._id
                          ? { ...i, tempRating: e.target.value }
                          : i
                      ))
                    }
                  />

                  <textarea
                    placeholder="Review"
                    style={styles.textarea}
                    onChange={(e) =>
                      setRequests(requests.map(i =>
                        i._id === req._id
                          ? { ...i, tempComment: e.target.value }
                          : i
                      ))
                    }
                  />

                  <button
                    style={styles.btn}
                    onClick={() =>
                      submitFeedback(req._id, req.tempRating, req.tempComment)
                    }
                  >
                    Submit
                  </button>

                </div>
              )}

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

/* ===================== UI STYLES ===================== */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white"
  },

  wrapper: {
    display: "flex",
    gap: "20px",
    padding: "20px",
    maxWidth: "1200px",
    margin: "auto"
  },

  panel: {
    flex: 1,
    background: "#111827",
    padding: "20px",
    borderRadius: "16px",
    border: "1px solid #f97316"
  },

  title: {
    color: "#f97316",
    marginBottom: "15px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginBottom: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white"
  },

  btn: {
    width: "100%",
    padding: "12px",
    background: "#f97316",
    border: "none",
    borderRadius: "10px",
    color: "white",
    cursor: "pointer"
  },

  card: {
    background: "#1f2937",
    padding: "15px",
    borderRadius: "12px",
    marginBottom: "15px"
  },

  row: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  accept: {
    flex: 1,
    background: "green",
    border: "none",
    padding: "8px",
    color: "white",
    borderRadius: "8px"
  },

  reject: {
    flex: 1,
    background: "red",
    border: "none",
    padding: "8px",
    color: "white",
    borderRadius: "8px"
  },

  textarea: {
    width: "100%",
    height: "70px",
    marginTop: "10px",
    padding: "10px",
    borderRadius: "10px",
    background: "#1f2937",
    border: "1px solid #f97316",
    color: "white"
  }
};
